import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import {
  updateCartItemRequest,
  removeFromCartRequest,
  clearCartRequest,
} from '../redux/slices/cartSlice';
import { API_URL } from '../utils/api';

const Cart = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { items, totalAmount, loading } = useSelector((state) => state.cart);
  const { isAuthenticated } = useSelector((state) => state.auth);

  const handleQuantityChange = (productId, quantity) => {
    dispatch(updateCartItemRequest({ productId, quantity }));
  };

  const handleRemove = (productId) => {
    dispatch(removeFromCartRequest({ productId }));
  };

  const handleClearCart = () => {
    if (window.confirm('Are you sure you want to clear your cart?')) {
      dispatch(clearCartRequest());
    }
  };

  const handleCheckout = () => {
    if (!isAuthenticated) {
      navigate('/login?redirect=checkout');
    } else {
      navigate('/checkout');
    }
  };

  if (items.length === 0) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-20 text-center">
        <h1 className="text-2xl font-bold mb-4">Your cart is empty</h1>
        <p className="text-gray-600 mb-8">Add some products to get started</p>
        <Link to="/products" className="btn-primary">
          Continue Shopping
        </Link>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-2xl font-bold">Shopping Cart</h1>
        <button onClick={handleClearCart} className="text-red-600 hover:text-red-700 text-sm">
          Clear Cart
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Cart Items */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-lg shadow">
            {items.map((item) => (
              <div key={item.productId} className="flex gap-4 p-4 border-b last:border-b-0">
                <img
                  src={item.image ? `${API_URL}${item.image}` : 'https://via.placeholder.com/100'}
                  alt={item.productName}
                  className="w-24 h-24 object-cover rounded"
                />
                <div className="flex-1">
                  <Link
                    to={`/product/${item.productId}`}
                    className="font-semibold hover:text-primary-600"
                  >
                    {item.productName}
                  </Link>
                  <p className="text-primary-600 font-medium mt-1">
                    ₦{item.price?.toLocaleString()}
                  </p>
                  <div className="flex items-center gap-4 mt-2">
                    <div className="flex items-center border rounded">
                      <button
                        onClick={() => handleQuantityChange(item.productId, item.quantity - 1)}
                        className="px-3 py-1 hover:bg-gray-100"
                        disabled={loading}
                      >
                        -
                      </button>
                      <span className="px-3 py-1 border-x">{item.quantity}</span>
                      <button
                        onClick={() => handleQuantityChange(item.productId, item.quantity + 1)}
                        className="px-3 py-1 hover:bg-gray-100"
                        disabled={loading}
                      >
                        +
                      </button>
                    </div>
                    <button
                      onClick={() => handleRemove(item.productId)}
                      className="text-red-600 hover:text-red-700 text-sm"
                      disabled={loading}
                    >
                      Remove
                    </button>
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-semibold">₦{item.subtotal?.toLocaleString()}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Order Summary */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-lg shadow p-6 sticky top-20">
            <h2 className="text-lg font-semibold mb-4">Order Summary</h2>
            <div className="space-y-2 mb-4">
              <div className="flex justify-between">
                <span className="text-gray-600">Subtotal</span>
                <span>₦{totalAmount?.toLocaleString()}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-600">Shipping</span>
                <span className="text-green-600">Free</span>
              </div>
            </div>
            <div className="border-t pt-4 mb-6">
              <div className="flex justify-between text-lg font-semibold">
                <span>Total</span>
                <span>₦{totalAmount?.toLocaleString()}</span>
              </div>
            </div>
            <button onClick={handleCheckout} className="btn-primary w-full">
              {isAuthenticated ? 'Proceed to Checkout' : 'Login to Checkout'}
            </button>
            {!isAuthenticated && (
              <p className="text-sm text-gray-500 mt-2 text-center">
                Don't have an account?{' '}
                <Link to="/register?redirect=checkout" className="text-primary-600">
                  Register
                </Link>
              </p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Cart;
